  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { useTranslation } from 'react-i18next';
  4	import { CheckIcon } from '@patternfly/react-icons';
  5	import {
  6	  Alert,
  7	  Card,
  8	  CardBody,
  9	  CardTitle,
 10	  Divider,
 11	  Grid,
 12	  GridItem,
 13	  Label,
 14	} from '@patternfly/react-core';
 15	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 16	import { SummaryProps, useInterval } from './utils';
 17	import { PipelineModel, RepositoryModel } from '../../models';
 18	import { getResultsSummary } from '../utils/summary-api';
 19	import { ALL_NAMESPACES_KEY } from '../../consts';
 20	import { getDropDownDate } from './dateTime';
 21	import { LoadingInline } from '../Loading';
 22	import { DataType, FLAGS } from '../../types';
 23	
 24	import './PipelineRunsTotalCard.scss';
 25	
 26	interface PipelinesRunsDurationProps {
 27	  namespace: string;
 28	  timespan: number;
 29	  interval: number;
 30	  summaryData?: SummaryProps;
 31	  bordered?: boolean;
 32	}
 33	
 34	const PipelinesRunsTotalCard: React.FC<PipelinesRunsDurationProps> = ({
 35	  namespace,
 36	  timespan,
 37	  interval,
 38	  bordered,
 39	}) => {
 40	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 41	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
 42	
 43	  const [totalRun, setTotalRun] = React.useState(0);
 44	  const [plrRun, setPlrRun] = React.useState(0);
 45	  const [repoRun, setRepoRun] = React.useState(0);
 46	  const [loaded, setLoaded] = React.useState(false);
 47	  const [pipelineRunsTotalError, setPipelineRunsTotalError] = React.useState<
 48	    string | undefined
 49	  >();
 50	  const abortControllerRefPipeline = React.useRef<AbortController>();
 51	  const abortControllerRefRepo = React.useRef<AbortController>();
 52	  const abortControllerRefAll = React.useRef<AbortController>();
 53	
 54	  if (namespace == ALL_NAMESPACES_KEY) {
 55	    namespace = '-';
 56	  }
 57	
 58	  React.useEffect(() => {
 59	    setLoaded(false);
 60	    setPipelineRunsTotalError(undefined);
 61	    // Clear stale data when namespace or timespan changes
 62	    setTotalRun(0);
 63	    setPlrRun(0);
 64	    setRepoRun(0);
 65	  }, [namespace, timespan]);
 66	
 67	  React.useEffect(() => {
 68	    return () => {
 69	      abortControllerRefPipeline.current?.abort();
 70	      abortControllerRefRepo.current?.abort();
 71	      abortControllerRefAll.current?.abort();
 72	    };
 73	  }, []);
 74	
 75	  const date = getDropDownDate(timespan).toISOString();
 76	
 77	  const getSummaryData = (filter, setData, controller) => {
 78	    setData(0);
 79	    setPipelineRunsTotalError(undefined);
 80	    setLoaded(false);
 81	    getResultsSummary(
 82	      namespace,
 83	      {
 84	        summary: 'total',
 85	        data_type: DataType?.PipelineRun,
 86	        filter,
 87	      },
 88	      undefined,
 89	      isDevConsoleProxyAvailable,
 90	      controller?.signal,
 91	      90000,
 92	    )
 93	      .then((response) => {
 94	        setLoaded(true);
 95	        setPipelineRunsTotalError(undefined);
 96	        setData(response?.summary?.[0]?.total || 0);
 97	      })
 98	      .catch((e) => {
 99	        if (e.name === 'AbortError') {
100	          // Request was cancelled, this is expected behavior
101	          return;
102	        }
103	        setLoaded(true);
104	        setPipelineRunsTotalError(
105	          e.message || t('Failed to load total runs data'),
106	        );
107	        setData(0);
108	      });
109	  };
110	
111	  const pipelineFilter = `data.spec.pipelineRef.contains("name") && data.status.startTime>timestamp("${date}")`;
112	  useInterval(
113	    () => {
114	      abortControllerRefPipeline.current?.abort();
115	      abortControllerRefPipeline.current = new AbortController();
116	      getSummaryData(
117	        pipelineFilter,
118	        setPlrRun,
119	        abortControllerRefPipeline.current,
120	      );
121	    },
122	    interval,
123	    namespace,
124	    date,
125	  );
126	
127	  const pacFilter = `data.metadata.labels.contains("pipelinesascode.tekton.dev/repository") && data.status.startTime>timestamp("${date}")`;
128	  useInterval(
129	    () => {
130	      abortControllerRefRepo.current?.abort();
131	      abortControllerRefRepo.current = new AbortController();
132	      getSummaryData(pacFilter, setRepoRun, abortControllerRefRepo.current);
133	    },
134	    interval,
135	    namespace,
136	    date,
137	  );
138	
139	  const allFilter = `data.status.startTime>timestamp("${date}")`;
140	  useInterval(
141	    () => {
142	      abortControllerRefAll.current?.abort();
143	      abortControllerRefAll.current = new AbortController();
144	      getSummaryData(allFilter, setTotalRun, abortControllerRefAll.current);
145	    },
146	    interval,
147	    namespace,
148	    date,
149	  );
150	
151	  return (
152	    <>
153	      <Card
154	        className={classNames('pipeline-overview__totals-card', {
155	          'card-border': bordered,
156	        })}
157	      >
158	        <CardTitle>
159	          <span>{t('Total runs')}</span>
160	        </CardTitle>
161	        <Divider />
162	        <CardBody>
163	          {pipelineRunsTotalError ? (
164	            <Alert
165	              variant="danger"
166	              isInline
167	              title={t('Unable to load total runs')}
168	              className="pf-v6-u-mb-md"
169	            />
170	          ) : (
171	            <>
172	              <Grid hasGutter className="pipeline-overview__totals-card__grid">
173	                <GridItem span={9}>
174	                  <span>
175	                    <Label
176	                      variant="outline"
177	                      className="pipeline-overview__totals-card__label"
178	                    >
179	                      {PipelineModel.abbr}
180	                    </Label>
181	                    {t('Runs in pipelines')}
182	                  </span>
183	                </GridItem>
184	                <GridItem
185	                  span={3}
186	                  className="pipeline-overview__totals-card__value"
187	                >
188	                  {loaded ? plrRun : <LoadingInline />}
189	                </GridItem>
190	              </Grid>
191	              <Grid hasGutter className="pipeline-overview__totals-card__grid">
192	                <GridItem span={9}>
193	                  <span>
194	                    <Label
195	                      variant="outline"
196	                      className="pipeline-overview__totals-card__repo-label"
197	                    >
198	                      {RepositoryModel.abbr}
199	                    </Label>
200	                    {t('Runs in repositories')}
201	                  </span>
202	                </GridItem>
203	                <GridItem
204	                  span={3}
205	                  className="pipeline-overview__totals-card__value"
206	                >
207	                  {loaded ? repoRun : <LoadingInline />}
208	                </GridItem>
209	              </Grid>
210	              <Grid hasGutter>
211	                <GridItem span={9}>
212	                  <span>
213	                    <CheckIcon className="pipeline-overview__totals-card__icon" />
214	                    {t('Total runs')}
215	                  </span>
216	                </GridItem>
217	                <GridItem
218	                  span={3}
219	                  className="pipeline-overview__totals-card__value"
220	                >
221	                  {loaded ? totalRun : <LoadingInline />}
222	                </GridItem>
223	              </Grid>
224	            </>
225	          )}
226	        </CardBody>
227	      </Card>
228	    </>
229	  );
230	};
231	
232	export default PipelinesRunsTotalCard;

